func TestRecoverabilityVerdict(t *testing.T) {
	const cutoff = int64(1000)
	tests := []struct {
		name            string
		screenshotOK    bool
		lastSnapshot    int64
		wantRecoverable bool
		wantFresh       bool
	}{
		{"fresh and verified", true, 1500, true, true},
		{"fresh but screenshot failed", false, 1500, false, true},
		{"verified but stale", true, 500, false, false},
		{"stale and failed", false, 500, false, false},
		{"never backed up", true, 0, false, false},
		{"exactly at cutoff is fresh", true, 1000, true, true},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			recoverable, fresh := recoverabilityVerdict(tt.screenshotOK, tt.lastSnapshot, cutoff)
			if recoverable != tt.wantRecoverable || fresh != tt.wantFresh {
				t.Fatalf("recoverabilityVerdict(%v, %d, %d) = (%v, %v), want (%v, %v)",
					tt.screenshotOK, tt.lastSnapshot, cutoff, recoverable, fresh, tt.wantRecoverable, tt.wantFresh)
			}
		})
	}
}

